  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is an interactive optimization task involving spatial search and pattern matching. I will break it down into strategy design, implementation of the interaction loop, and the core search algorithm.",
  "helpers": [
    {
      "label": "strategy_designer",
      "instructions": "Propose an optimal probing strategy to minimize cost. Compare the efficiency of single-cell queries (q 1) versus multi-cell noisy aggregate queries (q k) given the polyomino shapes. Determine how to use the noisy aggregate data to narrow down the search space for the hidden shapes."
    },
    {
      "label": "algorithm_developer",
      "instructions": "Design a pattern-matching algorithm that takes the results of the queries and the known polyomino shapes to reconstruct the most likely locations of the oil fields. The algorithm should handle the noise parameter mentioned in the input."
    },
    {
      "label": "implementation_engineer",
      "instructions": "Write the boilerplate for the main.py interactive loop. This includes reading the initial grid/shape input from stdin, implementing the stdout command writing with flushing, and reading the tester responses. Ensure the final answer is submitted using the 'a k x1 y1 ... xk yk' format."
    }
  ],
  "synthesis_brief": "Combine the probing strategy and the pattern-matching algorithm into a cohesive main.py script. The script must follow the interaction protocol strictly: read initial parameters, execute queries based on the strategy, process responses using the algorithm, and finally output the predicted oil cells."
}

